defmodule BlogWeb.PostLive do
  use Phoenix.LiveView

  def mount(_params, _session, socket) do
    {:ok, assign(socket, :post, nil)}
  end

  def render(assigns) do
    ~L"""
    <div>
      <%= raw @post.content %>
    </div>
    """
  end
end

defmodule BlogWeb.PostLive.Form do
  use Phoenix.LiveView.Component

  def mount(_params, _session, socket) do
    {:ok, assign(socket, :post, %{})}
  end

  def render(assigns) do
    ~L"""
    <form phx-submit="submit">
      <textarea name="content" phx-debounce="500"><%= @post.content %></textarea>
      <button type="submit">Submit</button>
    </form>
    """
  end

  def handle_event("submit", %{"content" => content}, socket) do
    {:noreply, assign(socket, :post, %{content: content})}
  end
end